import React from 'react'
import { I18n } from 'react-i18nify-lite'
import CommonHome from '../common/home'

const initName = () => {
  if(window.Android){
    return window.Android.initName();
  }else{
    return 'Android device';
  }
}

const initUserFree = () => {
  if(window.Android){
    return window.Android.initUserFree();
  }else{
    return true;
  }
}

const DEV_TWO_STEP = true

const hasRecentAuth = () => {
  return window.Android ? window.Android.isTimePasswordOk() : false
}

class androidHome extends React.Component {
  constructor(props) {
    super(props)
    this.state = {
      showDialog: false,
      tipo: '',
      twoStep: false,
      data: {},
      isLoading: false,
      name: initName(),
      passwordType: 'password',
      capsLockOn: false,
      userFree: initUserFree(),
    }
  }

  errorsFor = (name) => {
    const errors = this.state.data[name]
    if(!errors) return
    if(errors.length === 0) return

    return <div className="info info-error">{
      errors.map((o,i)=>(
          <p key={i}>{o}</p>
        )
      )}
      </div>
  }

  handleClose = (ev) => {
    this.setState({ showDialog: false })
  }

  handleRename = (ev) => {
    if(hasRecentAuth()){
      this.props.history.push(`/${I18n._locale}/rename`);
    }else{
      this.callHandleRename()
    }
  }

  callHandleRename = (ev) => {
    this.setState({ data: {} })
    if(window.Android){
      this.setState({ twoStep: window.Android.getTwoStepEnabled() })
    }else{
      this.setState({ twoStep: DEV_TWO_STEP })
    }
    this.setState({
      tipo: 'rename',
      showDialog: !this.state.showDialog
    })
  }

  handleLogin = (ev) => {
    if(hasRecentAuth()){
      if(window.Android){
        window.Android.openPanelWeb()
      } else {
        alert('open panel web');
      }
    }else{
      this.callHandleLogin()
    }
  }

  callHandleLogin = (ev) => {
    this.setState({ data: {} })
    if(window.Android){
      this.setState({ twoStep: window.Android.getTwoStepEnabled() })
    }else{
      this.setState({ twoStep: DEV_TWO_STEP })
    }
    this.setState({
      tipo: 'login',
      showDialog: !this.state.showDialog
    })
  }

  handleSettings = (ev) => {
    if(hasRecentAuth()){
      this.props.history.push(`/${I18n._locale}/security`);
    }else{
      this.callHandleSettings()
    }
  }

  callHandleSettings = (ev) => {
    if(window.Android){
      this.setState({ twoStep: window.Android.getTwoStepEnabled() })
    }else{
      this.setState({ twoStep: DEV_TWO_STEP })
    }
    this.setState({
      tipo:'setting',
      showDialog: !this.state.showDialog
    })
  }

  handlePassword = (ev) => {
    this.setState(
      { data: {}, isLoading: true },
      ()=>{setTimeout(this.callLogin, 0) }
    )
  }

  handleShowPassword = (e) => {
    this.setState({
      passwordType: this.state.passwordType === 'password' ? 'text' : 'password'
    })
  }

  touch = () => {
    if(window.Android){
      window.Android.touch();
    }
    this.setState({ capsLockOn: false });
    if(window.Android){
      this.verificateTab(20)
    }else{
      this.verificateTab(1)
    }
  }

  verificateTab = (counter) =>{
    counter=counter-1;
    this.changeTab()
    if(counter>0){
      if(window.Android){
        setTimeout(() => this.verificateTab(counter), 1000);
      }else{
        alert("verificateTab:"+counter);
        setTimeout(() => this.verificateTab(counter), 1000)
      }
    }
  }

  changeTab = () => {
    let capsLock=this.state.capsLockOn
    if(window.Android){
      capsLock=window.Android.capsLockOn();
    }else{
      capsLock=!capsLock;
    }
    this.setState({ capsLockOn: capsLock })
  }

  callLogin = () => {
    let passlogin=document.getElementById('passlogin').value
    let passlogin2=""
    try{
      passlogin2=document.getElementById('passlogin2').value
    }catch(error) {}
    if(window.Android){
      let json=window.Android.login_tipo(''+passlogin,passlogin2,this.state.tipo);
      this.setState(
        { data: JSON.parse(json), isLoading: false },
        ()=>{setTimeout(this.callExit,0,json) }
      )
    } else{
      let json='{"result":true}'
      setTimeout(()=>{
        this.setState(
          { data: JSON.parse(json), isLoading: false },
          ()=>{setTimeout(this.callExit, 0,json)}
        )
      }, 5000)
    }
  }

  callExit = (jsonSt) => {
    let result=false
    try{
      let json=JSON.parse(jsonSt)
      if(jsonSt.includes("result"))
        result=json.result
      if(result){
        if(this.state.tipo==='setting'){
          this.props.history.push(`/${I18n._locale}/security`);
        }else{
          this.props.history.push(`/${I18n._locale}/rename`);
        }
      }
    }catch(err){
    }
  }

  handleForgot = (ev) => {
    if(window.Android){
      window.Android.forgot()
    } else{
      alert("ola forgot")
    }
  }

  handleFocus = (e) => {
    this.setState({data: {}})
  }

  handleChangeInput = () => {
    let passlogin=document.getElementById('passlogin').value;
    if(window.Android){
      window.Android.inputwebview(passlogin,this.state.tipo);
    }else{
      alert('passlogin:'+passlogin+" protected tipo:"+this.state.tipo);
    }
  }

  render() {
    return (
      <CommonHome
        name={this.state.name}
        onRename={this.handleRename}
        onLogin={this.handleLogin}
        onSettings={this.handleSettings}
        onClose={this.handleClose}
        onSubmit={this.handlePassword}
        onForgot={this.handleForgot}
        showDialog={this.state.showDialog}
        twoStep={this.state.twoStep}
        showUninstall={this.state.userFree}
        uninstallHref={I18n.t(`uninstall_prey_link`)}
        passwordType={this.state.passwordType}
        onTogglePassword={this.handleShowPassword}
        capsLockOn={this.state.capsLockOn}
        onPasswordClick={this.touch}
        onPasswordFocus={this.handleFocus}
        onInputChange={this.handleChangeInput}
        onFormFocus={this.handleFocus}
        isLoading={this.state.isLoading}
        errors={this.errorsFor("error")}
      />
    )
  }
}

export default androidHome;
