import React from 'react'
import { I18n } from 'react-i18nify-lite'
import { Dialog, Loading } from '../assets/Dialog'
import { motion } from 'framer-motion'
import { Group, Space, Layout } from '../assets/stash'
import settingsIcon from '../assets/icons/settings.svg'

const Logo = ({ duration = 2, scale = 0.8, stroke = "rgba(255,255,255,0.40)", fill = "transparent" }) => {
  return (
    <svg className="iso" viewBox="273.029 152.065 128 128">
      <motion.path
        initial={{ opacity: 0, pathLength: 0, pathOffset: 1 }}
        animate={{ opacity: 1, pathLength: 1, pathOffset: [1, 0], scale }}
        exit={{ opacity: 0 }}
        transition={{ duration, ease: "easeOut" }}
        d="M337.033 155.783l-20.214 11.67 13.475 7.776 6.72-3.89 6.754 3.886 13.471-7.78-20.206-11.662zm.004 120.564l50.522-29.17v-31.113l-13.478 7.78.004 15.556-37.051 21.393-37.054-21.397V223.84l-13.471-7.776v31.113l50.528 29.17zm57.257-95.292v.011l.007 15.549-47.163 27.23 13.463 7.78-23.568 13.613-23.576-13.613 13.471-7.78-47.163-27.23.007-15.538-6.743-3.898v-19.443l57.257 33.052 6.747-3.886 6.728 3.886 57.268-33.063v19.443l-6.735 3.887z"
        stroke={stroke}
        fill={fill}
        strokeWidth="1"
      />
    </svg>
  );
}

const EyeIcon = () => (
  <svg className="login-password-toggle-icon" viewBox="0 0 24 24" aria-hidden="true" focusable="false">
    <path
      d="M12 6.75c4.84 0 8.36 3.93 9.53 5.44c.2.26.2.62 0 .88C20.36 14.57 16.84 18.5 12 18.5s-8.36-3.93-9.53-5.43a.73.73 0 0 1 0-.88C3.64 10.68 7.16 6.75 12 6.75Zm0 2a3.94 3.94 0 1 0 0 7.88a3.94 3.94 0 0 0 0-7.88Zm0 1.9a2.04 2.04 0 1 1 0 4.08a2.04 2.04 0 0 1 0-4.08Z"
      fill="currentColor"
    />
  </svg>
);

const EyeOffIcon = () => (
  <svg className="login-password-toggle-icon" viewBox="0 0 24 24" aria-hidden="true" focusable="false">
    <path
      d="M4.28 3.22a.75.75 0 1 0-1.06 1.06l3.05 3.05c-1.7 1.18-2.94 2.65-3.8 3.76a.73.73 0 0 0 0 .88C3.64 13.48 7.16 17.4 12 17.4c1.92 0 3.6-.62 5.03-1.53l2.69 2.69a.75.75 0 1 0 1.06-1.06L4.28 3.22Zm7.72 5.53a3.94 3.94 0 0 1 3.94 3.94c0 .68-.17 1.32-.47 1.88l-5.35-5.35c.56-.3 1.2-.47 1.88-.47Zm7.53 3.34c-.75-.96-1.77-2.19-3.11-3.28a10.18 10.18 0 0 0-2.04-1.28a8.38 8.38 0 0 0-6.49-.24l1.61 1.61A5.4 5.4 0 0 1 12 8.25c2.21 0 4.01 1.8 4.01 4.01c0 .53-.1 1.03-.28 1.48l1.42 1.42c.91-.83 1.63-1.75 2.38-2.7c.2-.26.2-.62 0-.88Z"
      fill="currentColor"
    />
  </svg>
);

const CommonHome = ({
  name,
  onRename,
  onLogin,
  onSettings,
  onClose,
  onSubmit,
  onForgot,
  showDialog = false,
  twoStep = false,
  showUninstall = false,
  uninstallHref,
  passwordType = 'password',
  onTogglePassword,
  capsLockOn = false,
  onPasswordClick,
  onPasswordFocus,
  onInputChange,
  onFormFocus,
  isLoading = false,
  errors,
}) => {
  return (
    <Layout scrollableFix={true} className="activation home fs-onboarding regular inverted">
      <div className="container main-info">
        <div className="column">
          <div className="device-name">
            <p>{I18n.t(`device_name`)}</p>
            <span id="name_device_0">
              <a onClick={onRename} href="#/" className="btn icon-pencil device-name-chip">
                <span id="name_device_1">{name}</span>
              </a>
            </span>
          </div>

          <h2 className="status-summary">
            <small>{I18n.t(`current_status`)}</small>
            <br/>
            <div className="status">
              <span id="txtStatusDevice">{I18n.t(`status.protected`)}</span>
            </div>
          </h2>

          <figure className="anime uno">
            <figure className="anime dos">
              <figure className="anime tres">
                <Logo />
              </figure>
            </figure>
          </figure>
        </div>
      </div>
      <Group className="homeOptions">
        <Group className="ctas">
          <a onClick={onLogin} href="#/" className="ob-btn ob-btn-compact btn-centered">
            <span className="home-cta-label">{I18n.t(`login`)}</span>
          </a>
          <a onClick={onSettings} href="#/" className="ob-btn ob-btn-compact btn-centered ob-btn-secondary">
            <img src={settingsIcon} alt="" className="home-cta-icon" />
            <span className="home-cta-label">{I18n.t(`settings`)}</span>
          </a>
        </Group>
        {showUninstall ? (
          <a href={uninstallHref} className="btn uninstall-info">
            <small className="tac">{I18n.t(`uninstall_prey`)}</small>
          </a>
        ) : null}
      </Group>
      {showDialog ? (
        <Dialog className={`dialog`}>
          <div className="inner" key={'pin'}>
            <a onClick={onClose} className="close btn transparent default-text icon-cancel" />
            <form autoComplete="off" className="form form-session" id="new-session" acceptCharset="UTF-8" onFocus={onFormFocus}>
              <ul className="form hvv">
                <li className="superpassword">
                  <label className="tag-label" htmlFor="passlogin">{I18n.t("dialog_login.holder")}</label>
                  <div className="login-password-field">
                    <input
                      type={passwordType}
                      name="password1"
                      id="passlogin"
                      tabIndex="1"
                      placeholder=" "
                      onFocus={onPasswordFocus}
                      onClick={onPasswordClick}
                      onChange={onInputChange}
                    />
                    <a
                      onClick={onTogglePassword}
                      className={`login-password-toggle ${passwordType === 'text' ? 'is-active' : ''}`}
                      aria-label={passwordType === 'text' ? 'Hide password' : 'Show password'}
                    >
                      {passwordType === 'text' ? <EyeOffIcon /> : <EyeIcon />}
                    </a>
                  </div>
                  {capsLockOn ? (
                    <div className="info info-warning"><p>{I18n.t("signup.capsLockIsOn")}</p></div>
                  ) : null}
                </li>
              </ul>
              {twoStep ? (
                <ul className="form hvv">
                  <li>
                    <label className="tag-label" htmlFor="passlogin2">{I18n.t("dialog_login.title2")}</label>
                    <input
                      type="tel"
                      inputMode="numeric"
                      pattern="[0-9]*"
                      maxLength="6"
                      name="password2"
                      id="passlogin2"
                      tabIndex="2"
                      placeholder=" "
                      onFocus={onPasswordFocus}
                      onClick={onPasswordClick}
                    />
                  </li>
                </ul>
              ) : null}
            </form>
            {errors}
            <Group className="vspace dialog-actions">
              <a onClick={onClose} className="ob-btn ob-btn-compact btn-centered ob-btn-secondary">{I18n.t(`dialog_login.cancel`)}</a>
              <Space />
              <a onClick={onSubmit} className="ob-btn ob-btn-compact btn-centered">
                <span>{I18n.t(`dialog_login.submit`)}</span>
              </a>
            </Group>
            <a onClick={onForgot} href="#/" className="dialog-forgot-link">
              {I18n.t(`dialog_login.forgot`)}
            </a>
          </div>
        </Dialog>
      ) : null}
      {isLoading ? (
        <Loading><code>{I18n.t(`dialog_login.loading`)}</code></Loading>
      ) : null}
      <div id="overall" />
    </Layout>
  );
}

export default CommonHome
