import React from 'react'
import { I18n } from 'react-i18nify-lite'
import CommonRename from '../common/rename'

const initName = () => {
  if (window.Android) {
    return window.Android.initName();
  } else {
    return 'Android device';
  }
}

const callRename = (newName) => {
  if (window.Android) {
    return JSON.parse(window.Android.rename2(newName));
  } else {
    return { code: 200, error: 'error', name: '' };
  }
}

export default class Rename extends React.Component {
  constructor(props) {
    super(props)
    this.state = {
      exists: false,
      name: initName(),
      isLoading: false,
      nameError: '',
    }
  }

  handleClickRename = () => {
    this.setState({ isLoading: true }, () => {
      setTimeout(this.processRename, 2000)
    })
  }

  processRename = () => {
    const newName = document.getElementById('newName').value;
    const result = callRename(newName);
    this.setState({ isLoading: false })

    if (result.code === 200) {
      this.props.history.push(`/${I18n._locale}/`);
    } else {
      this.setState({ nameError: result.error, exists: true })
    }
  }

  handleChange = () => {
    this.setState({ exists: false })
  }

  render() {
    return (
      <CommonRename
        name={this.state.name}
        onRename={this.handleClickRename}
        onChange={this.handleChange}
        isLoading={this.state.isLoading}
        nameError={this.state.nameError}
        exists={this.state.exists}
      />
    )
  }
}
