import React from "react";
import { I18n } from "react-i18nify-lite";
import CommonLogin from "../common/login";
import { sendMessageToIos } from "./commons";

const iosKeyboardBridge = {
  touch: () => {
    if (
      typeof window !== "undefined" &&
      window.PreyIOS &&
      typeof window.PreyIOS.touch === "function"
    ) {
      window.PreyIOS.touch();
    }
  },
  getCapsLockState: () => {
    if (
      typeof window !== "undefined" &&
      window.PreyIOS &&
      typeof window.PreyIOS.capsLockOn === "function"
    ) {
      return window.PreyIOS.capsLockOn();
    }

    return null;
  },
  pollCount:
    typeof window !== "undefined" &&
    window.PreyIOS &&
    typeof window.PreyIOS.capsLockOn === "function"
      ? 20
      : 1,
};

export default class Login extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      data: {},
      passwordType: "password",
    };
  }

  errorsFor = (name) => {
    const errors = this.state.data[name];
    if (!errors || errors.length === 0) return null;

    return (
      <span className="msg info-error">
        {errors.map((error, index) => (
          <span key={index}>{error}</span>
        ))}
      </span>
    );
  };

  handleClickLogin = () => {
    const emaillogin = encodeURIComponent(
      document.getElementById("emaillogin").value,
    );
    const passlogin = encodeURIComponent(
      document.getElementById("passlogin").value,
    );
    sendMessageToIos("login", {
      preyEmailLogin: emaillogin,
      preyPassLogin: passlogin,
    });
  };

  handleFocus = () => {
    this.setState({ data: {} });
  };

  handleShowPassword = (event) => {
    event.preventDefault();
    this.setState(({ passwordType }) => ({
      passwordType: passwordType === "password" ? "text" : "password",
    }));
  };

  handleClickQR = (event) => {
    event.preventDefault();
    sendMessageToIos("qrcode");
  };

  handleShowTerms = (event) => {
    event.preventDefault();
    sendMessageToIos("terms");
  };

  handleShowPrivacy = (event) => {
    event.preventDefault();
    sendMessageToIos("privacy");
  };

  handleShowForgot = (event) => {
    event.preventDefault();
    sendMessageToIos("forgot");
  };

  handleWhatsPrey = (event) => {
    event.preventDefault();
    this.props.history.push(`/${I18n._locale}/whatsprey`);
  };

  render() {
    return (
      <CommonLogin
        passwordType={this.state.passwordType}
        onFocus={this.handleFocus}
        onTogglePassword={this.handleShowPassword}
        onSubmit={this.handleClickLogin}
        onQr={this.handleClickQR}
        onWhatsPrey={this.handleWhatsPrey}
        onForgot={this.handleShowForgot}
        onTerms={this.handleShowTerms}
        onPrivacy={this.handleShowPrivacy}
        passwordError={this.errorsFor("error")}
        keyboardBridge={iosKeyboardBridge}
      />
    );
  }
}
