import React, { Component } from 'react'
import CommonHome from '../common/home'
import { sendMessageToIos, isNativeWindows } from './commons'

const initName = () => {
  if (isNativeWindows()) {
    sendMessageToIos("namedevice", {openPanelWeb: true});
    return ""
  } else {
    return "iOS device"
  }
}

class Home extends Component {
  constructor(props) {
    super(props)
    this.state = {
      showDialog: false,
      isLoading: false,
      handleAction: "",
      passwordType: 'password',
      name: initName(),
    }
  }

  handleRename = (ev) => {
    ev.preventDefault()
    if (!this.state.showDialog) {sendMessageToIos("checktouchid", {openPanelWeb: "rename"});}
    this.setState({
      showDialog: !this.state.showDialog,
      handleAction: "renamepwd",
    })
  }

  handleLogin = (ev) => {
    ev.preventDefault()
    if (!this.state.showDialog) {sendMessageToIos("checktouchid", {openPanelWeb: "panel"});}
    this.setState({
      showDialog: !this.state.showDialog,
      handleAction: "panelpwd",
    })
  }

  handleSettings = (ev) => {
    ev.preventDefault()
    if (!this.state.showDialog) {sendMessageToIos("checktouchid", {openPanelWeb: "settings"});}
    this.setState({
      showDialog: !this.state.showDialog,
      handleAction: "settingspwd",
    })
  }

  handleClose = (ev) => {
    this.setState({ showDialog: false })
  }

  handleSubmit = (ev) => {
    sendMessageToIos(this.state.handleAction, { pwdLogin: document.getElementById('passlogin').value })
  }

  handleForgot = (ev) => {
    sendMessageToIos("forgot")
  }

  handleShowPassword = (e) => {
    this.setState({
      passwordType: this.state.passwordType === 'password' ? 'text' : 'password'
    })
  }

  render() {
    return (
      <CommonHome
        name={this.state.name}
        onRename={this.handleRename}
        onLogin={this.handleLogin}
        onSettings={this.handleSettings}
        onClose={this.handleClose}
        onSubmit={this.handleSubmit}
        onForgot={this.handleForgot}
        showDialog={this.state.showDialog}
        passwordType={this.state.passwordType}
        onTogglePassword={this.handleShowPassword}
        isLoading={this.state.isLoading}
      />
    )
  }
}

export default Home
