import React, { useEffect } from 'react'
import { withRouter } from 'react-router-dom'
import { Wizard, Steps, Step } from 'react-albus'
import { I18n } from 'react-i18nify-lite'


const Activation = ({ history }) => {
  useEffect(() => {
    const redirectTimeout = setTimeout(() => {
      history.push(`/${I18n._locale}/index`)
    }, 3000)

    return () => clearTimeout(redirectTimeout)
  }, [history])

  return (
    <div className="activation fs-onboarding regular inverted">
      <div className="column">
        <Wizard>
          <Steps>
            <Step id="try" render={({ next }) => (
                <div className="container">
                  <div id="done" className="column">
                    <h4 className="tac">{I18n.t("activation.you_ready")}</h4>
                    <figure className="anime uno">
                      <figure className="anime dos">
                        <figure className="anime tres">
                          <i className="icon-shield-4"/>
                        </figure>
                      </figure>
                    </figure>
                    <h2><small>{I18n.t("activation.status")}</small>
                    <br/>{I18n.t("activation.protected")}</h2>
                  </div>
                </div>
              )}
            />
          </Steps>
        </Wizard>
      </div>
    </div>
  )
}

export default withRouter(Activation)
