import React from "react";
import { Link } from "react-router-dom";
import { I18n } from "react-i18nify-lite";
import { Group } from "../assets/stash";
import loc from "../images/onboarding/ilust/4.svg";
import logomono from "../images/branding/prey-logo-monotono-alt.svg";
import LegalFooter from "../common/LegalFooter";

export default class BgLoc extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
       data: {},
    }
  }

  handleClickApprove = (e) => {
    if (window.Android) {
      window.Android.approveLocation();
    } else {
      this.props.history.push(`/${I18n._locale}/signin`);
    }
  }

  handleClickSkip = (e) => {
    if (window.Android) {
      window.Android.skipPermissionsBg();
      if(window.Android.skipLocation()){
        if(window.Android.initConfigure()){
          this.props.history.push(`/${I18n._locale}/`);
        }else{
          this.props.history.push(`/${I18n._locale}/signin`);
        }
      }else{
        this.props.history.push(`/${I18n._locale}/permissions`);
      }
    } else {
      this.props.history.push(`/${I18n._locale}/signin`);
    }
    
  }


  render() {
    return (
      <div className="security fs-onboarding regular inverted android-bgloc-redesign">
        <div className="column">
          <div className="android-bgloc-header">
            <img src={logomono} alt="Prey" className="permissions-brand-logo" />
            <Link
              to="#"
              onClick={this.handleClickSkip}
              className="android-bgloc-skip"
            >
              {I18n.t("bgloc.skip")}
            </Link>
          </div>
          <div className="android-bgloc-panel">
            <h4 className="heading">{I18n.t("bgloc.title")}</h4>
            <p className="android-bgloc-copy">{I18n.t("bgloc.body1")}.</p>
            <figure className="android-bgloc-figure">
              <img src={loc} className="first" alt="location" />
            </figure>
            <Group className="android-bgloc-actions">
              <Link to="#" onClick={this.handleClickApprove} className="ob-btn ob-btn-compact btn-centered">
                <span>{I18n.t("bgloc.approve")}</span>
              </Link>
            </Group>
          </div>
        </div>
        <LegalFooter />
      </div>
    );
  }
}
