import React from "react";
import preyLogo from "../images/branding/prey-logo-monotono-alt.svg";
import { Link } from "react-router-dom";
import { I18n } from "react-i18nify-lite";
import one from "../images/onboarding/ilust/1.svg";
import two from "../images/onboarding/ilust/2.svg";
import three from "../images/onboarding/ilust/3.svg";
import four from "../images/onboarding/ilust/4.svg";
import five from "../images/onboarding/ilust/5.svg";

const onboardingType = process.env.REACT_APP_ONBOARDING_TYPE || "android";
const getPermissionsEntryPath = () =>
  onboardingType === "android"
    ? `/${I18n._locale}/permissions`
    : `/${I18n._locale}/permissions`;

const slides = [
  {
    headKey: "onboarding.first.head",
    bodyKey: "onboarding.first.body",
    figureClass: "secHub",
    images: [
      { src: one, className: "first" },
    ],
  },
  {
    headKey: "onboarding.second.head",
    bodyKey: "onboarding.second.body",
    figureClass: "trkFnd",
    images: [{ src: two}],
  },
  {
    headKey: "onboarding.third.head",
    bodyKey: "onboarding.third.body",
    figureClass: "",
    images: [{ src: three}],
  },
  {
    headKey: "onboarding.fourth.head",
    bodyKey: "onboarding.fourth.body",
    figureClass: "",
    images: [{ src: four}],
  },
  {
    headKey: "onboarding.fifth.head",
    bodyKey: "onboarding.fifth.body",
    figureClass: "",
    images: [{ src: five}],
  },
];

class OnBoarding extends React.Component {
  constructor(props) {
    super(props);
    this.state = { currentSlide: 0 };
    this.touchStartX = 0;
  }

  get showSkip() {
    return this.props.showSkip !== false;
  }

  get finishPath() {
    return this.props.finishPath || getPermissionsEntryPath();
  }

  handleStart = (x) => {
    this.touchStartX = x;
  };

  handleEnd = (x) => {
    const diff = this.touchStartX - x;
    const { currentSlide } = this.state;
    if (diff > 50 && currentSlide < slides.length - 1) {
      this.setState({ currentSlide: currentSlide + 1 });
    } else if (diff < -50 && currentSlide > 0) {
      this.setState({ currentSlide: currentSlide - 1 });
    }
  };

  handleTouchStart = (e) => this.handleStart(e.touches[0].clientX);
  handleTouchEnd = (e) => this.handleEnd(e.changedTouches[0].clientX);
  handleMouseDown = (e) => {
    this.dragging = true;
    this.handleStart(e.clientX);
  };
  handleMouseUp = (e) => {
    if (this.dragging) {
      this.dragging = false;
      this.handleEnd(e.clientX);
    }
  };

  render() {
    const { currentSlide } = this.state;
    const current = slides[currentSlide];
    return (
      <div
        className="ob-screen"
        onTouchStart={this.handleTouchStart}
        onTouchEnd={this.handleTouchEnd}
        onMouseDown={this.handleMouseDown}
        onMouseUp={this.handleMouseUp}
      >
        <div className="ob-header">
          <img src={preyLogo} alt="Prey" className="ob-logo" />
          {this.showSkip && (
            <Link to={this.finishPath} className="ob-skip">
              {I18n.t("onboarding.skip")}
            </Link>
          )}
          {this.props.showClose && (
            <Link to={this.finishPath} className="ob-close">
              <i className="icon-cancel" />
            </Link>
          )}
        </div>
        <div className="ob-dots">
          {slides.map((_, i) => (
            <span
              key={i}
              className={`ob-dot${i === currentSlide ? " active" : ""}`}
              onClick={() => this.setState({ currentSlide: i })}
            />
          ))}
        </div>
        <div className="ob-illustration">
          <figure
            className={`ob-figure ${current.figureClass}`}
            key={currentSlide}
          >
            <div className="bg" />
            {current.images.map((img, j) => (
              <img key={j} src={img.src} className={img.className} alt="" />
            ))}
          </figure>
        </div>
        <div className="ob-card">
          <h4 className="ob-title">{I18n.t(current.headKey)}</h4>
          <p className="ob-subtitle">{I18n.t(current.bodyKey)}</p>
          {currentSlide === 0 ? (
            <button
              className="ob-btn"
              onClick={() => this.setState({ currentSlide: currentSlide + 1 })}
            >
              {I18n.t("onboarding.start")}
            </button>
          ) : currentSlide < slides.length - 1 ? (
            <button
              className="ob-btn"
              onClick={() => this.setState({ currentSlide: currentSlide + 1 })}
            >
              {I18n.t("onboarding.continue")}
            </button>
          ) : (
            <button
              className="ob-btn"
              onClick={() => this.props.history.push(this.finishPath)}
            >
              {I18n.t("onboarding.continue")}
            </button>
          )}
        </div>
      </div>
    );
  }
}

export default OnBoarding;
