import React from "react";
import { Link } from "react-router-dom";
import { I18n } from "react-i18nify-lite";

const initVerifyLock = () => {
  if (window.Android) {
    window.Android.verifyLock();
  } else {
    alert('verifyLock');
  }
};

const verificateAlert = () => {
  if (window.Android) {
    return window.Android.verificateAlert();
  } else {
    alert('verifyAlert');
  }
};

export default class Lock extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      data: {},
      isLoading: false,
      passwordType: "password",
      capsLockOn: false,
      verifyLock: initVerifyLock(),
      isAlert: false,
      alertText: "",
      verificateAlert: verificateAlert(),
    };
  }

  componentDidMount() {}

  render() {
    return (
      <div className="login fs-onboarding regular inverted">
        <div className="column">
          <div className="sign-form">
            <h1 className="lock info text-warning">
              <small>{I18n.t("lock.access")}</small>
              <span>{I18n.t("lock.denied")}</span>
            </h1>

            <p>{I18n.t("lock.text1")}</p>
            <div className="info notice-custom">
              <p>"{this.state.verificateAlert}"</p>
            </div>
            <Link
              to={`/${I18n._locale}/lockmessage2`}
              className="btn lock-btn full"
            >
              <span>Ingresar contraseña para desbloquear</span>
            </Link>
          </div>
        </div>
      </div>
    );
  }
}
