import React from "react";
import CommonRename from "../common/rename";
import { sendMessageToIos, isNativeWindows } from "./commons";

const initName = () => {
  if (isNativeWindows()) {
    sendMessageToIos("namedevice", { openPanelWeb: true });
    return "";
  } else {
    return "iOS device";
  }
};

export default class Rename extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      data: {},
      exists: false,
      name: initName(),
      isLoading: false,
      nameError: "",
    };
  }

  errorsFor = (name) => {
    const errors = this.state.data[name];
    if (!errors) return;
    if (errors.length === 0) return;
    return (
      <div className="info info-error">
        {errors.map((o, i) => (
          <p key={i}>{o}</p>
        ))}
      </div>
    );
  };

  handleClickRename = (e) => {
    let newName = encodeURIComponent(document.getElementById("newName").value);
    sendMessageToIos("rename", { newName });
  };

  handleClickCancel = (ev) => {
    sendMessageToIos("index");
  };

  handleChange = (e) => {
    this.setState({ exists: false });
  };

  handleChangeName = (e) => {
    e.preventDefault();
    this.setState({
      name: document.getElementById("nametext").value,
    });
  };

  render() {
    return (
      <div>
        <CommonRename
          name={this.state.name}
          onRename={this.handleClickRename}
          onCancel={this.handleClickCancel}
          onChange={this.handleChange}
          isLoading={this.state.isLoading}
          errors={this.errorsFor("email")}
          nameError={this.state.nameError}
          exists={this.state.exists}
        />
        <input type="hidden" id="nametext" value="" />
        <button
          id="btnChangeName"
          className="hidden"
          onClick={this.handleChangeName}
        ></button>
      </div>
    );
  }
}
