import React from 'react'
import { I18n } from 'react-i18nify-lite'
import { Link } from 'react-router-dom'
import { Group } from 'prey-stash'

export default class Accessibility extends React.Component {

  constructor(props){
    super(props)
    this.state = {
      data: {},
    }
  }

  handleClickAccessibilitySkip = (e)=>{
  	if (window.Android) {
      window.Android.accessibilitySkip();
    } else {
      this.props.history.push(`/${I18n._locale}/security`);
    }
  }

  handleClickAccessibilityDeny = (e)=>{
  	if (window.Android) {
      window.Android.accessibilityDeny();
    } else {
      this.props.history.push(`/${I18n._locale}/security`);
    }
  }

  handleClickAccessibilityAgree = (e)=>{
  	if (window.Android) {
      window.Android.accessibilityAgree();
    } else {
      this.props.history.push(`/${I18n._locale}/security`);
    }
  }

  render() {
    return (
		<div className="security fs-onboarding regular inverted help-form">
		    <Group>
		        <a onClick={this.handleClickAccessibilitySkip}>
		          <div className="btn fill help-center accessibility-view">
		            <span className="tac2">{I18n.t("accesibility.skip")}</span>
		            <span className='icon-right-open-big'/>
		          </div>
		        </a>
		    </Group>
		    <br/>
	        <div className="container">
	        	<h4 className="heading">
            		{I18n.t("accesibility.title")}
          		</h4>
          		<br/>
          		<p>
            		{I18n.t("accesibility.text1")}
          		</p>
          		<br/>
          		<p>
            		{I18n.t("accesibility.text2")}
          		</p>
          		<br/>
          		<h5>
            		{I18n.t("accesibility.text3")}
          		</h5>
			</div>
			<Group className="homeOptions">
          		<Group className="ctas">
            		<Link to="#" onClick={this.handleClickAccessibilityDeny} className="btn alt flex">
              			<span>{I18n.t("accesibility.deny")}</span>
            		</Link>
            		<Link to="#" onClick={this.handleClickAccessibilityAgree} className="ob-btn ob-btn-compact btn-centered">
              			<span>{I18n.t("accesibility.agree")}</span>
            		</Link>
          		</Group>
        	</Group>
        </div>
		)
  }
}
