import React from 'react'
import { I18n } from 'react-i18nify-lite'

import CommonLogin from '../common/login'

const handleClickQR = (event, history) => {
  event.preventDefault()
  if (window.Android) {
    window.Android.qr()
  } else {
    history.push(`/${I18n._locale}/activation`)
  }
}

export default class Login extends React.Component {
  constructor(props) {
    super(props)
    this.state = {
      data: {},
      isLoading: false,
      passwordType: 'password',
    }
  }

  errorsFor = (name) => {
    const errors = this.state.data[name]
    if (!errors || errors.length === 0) return null

    return (
      <div className="info info-error">
        {errors.map((error, index) => <p key={index}>{error}</p>)}
      </div>
    )
  }

  handleClickLogin = (event) => {
    event.preventDefault()
    this.setState({ data: {}, isLoading: true }, () => {
      setTimeout(this.callHandleClickLogin, 0)
    })
  }

  callHandleClickLogin = () => {
    const emaillogin = document.getElementById('emaillogin').value
    const passlogin = document.getElementById('passlogin').value

    if (window.Android) {
      const json = window.Android.mylogin(`${emaillogin}`, `${passlogin}`)
      if (json !== '') {
        this.setState({
          data: JSON.parse(json),
          isLoading: false,
        })
      } else {
        this.props.history.push(`/${I18n._locale}/activation`)
      }
    } else {
      this.setState({
        data: { error: ['Credenciales inválidas'] },
        isLoading: false,
      })
    }
  }

  handleFocus = () => {
    this.setState({ data: {} })
  }

  handleShowPassword = (event) => {
    event.preventDefault()
    this.setState(({ passwordType }) => ({
      passwordType: passwordType === 'password' ? 'text' : 'password',
    }))
  }

  render() {
    return (
      <CommonLogin
        passwordType={this.state.passwordType}
        onFocus={this.handleFocus}
        onTogglePassword={this.handleShowPassword}
        onSubmit={this.handleClickLogin}
        onQr={(event) => handleClickQR(event, this.props.history)}
        onWhatsPrey={(e) => { e.preventDefault(); this.props.history.push(`/${I18n._locale}/whatsprey`) }}
        forgotHref="https://panel.preyproject.com/forgot"
        termsHref="https://preyproject.com/terms"
        privacyHref="https://preyproject.com/privacy"
        emailError={this.errorsFor('email')}
        passwordError={this.errorsFor('error')}
        keyboardBridge={{
          touch: () => {
            if (window.Android) {
              window.Android.touch()
            }
          },
          getCapsLockState: () => {
            if (window.Android) {
              return window.Android.capsLockOn()
            }

            return null
          },
          pollCount: window.Android ? 20 : 1,
        }}
        isLoading={this.state.isLoading}
      />
    )
  }
}
