import React from 'react'
import ReactDOM from 'react-dom'
import { I18n } from 'react-i18nify-lite'
import { HashRouter, Route, Switch } from 'react-router-dom'
import posed, { PoseGroup } from 'react-pose'
import {ThemeProvider, createGlobalStyle} from 'styled-components'
import { IconStyle, FormStyle } from 'prey-stash'

import {
  Segundo,
  dark,
  ButtonStyle,
  FeedbackStyle
} from './assets/stash'

import androidHome from "./android/home"
import androidLogin from "./android/login"
import androidActivation from "./android/activation"
import androidReport from "./android/report"
import androidPermissions from "./android/permissions"
import androidBgLoc from "./android/bgloc"
import androidSecurity from "./android/security"
import androidPrivacy from "./android/privacy"
import WhatsPrey from "./common/whatsprey"
import androidLock from "./android/lock"
import androidLockMessage from "./android/lockmessage"
import androidLockMessage2 from "./android/lockmessage2"
import androidPin from "./android/pin"
import androidRename from "./android/rename"
import androidLocation from "./android/location"
import androidChrome from "./android/chrome"
import androidAccessibility from "./android/accessibility"

import iosLogin from "./ios/login"
import iosActivation from "./ios/activation"
import iosHome from './ios/home';
import iosPermissions from './ios/permissions';
import iosRename from "./ios/rename"

import OnBoardingStyles, { obScreenCSS } from './onboarding/onboardingstyles';

import OnBoarding from "./common/start"

import { initLang } from './i18n/base';

import './assets/typography/style.css';

const onboardingType = process.env.REACT_APP_ONBOARDING_TYPE || 'android';

const GlobalStyle = createGlobalStyle`
  ${Segundo(dark)}
  ${ButtonStyle(dark)}
  ${FeedbackStyle(dark)}
  ${FormStyle(dark)}
  ${IconStyle(dark)}
  ${OnBoardingStyles(dark)}
  ${obScreenCSS(dark)}
`

const RouteContainer = posed.div({
  init: {
    opacity: 0,
  },
  enter: {
    opacity: 1,
    beforeChildren: true,
    staggerChildren: 50,
  },
  exit: {
    opacity: 0,
    staggerChildren: 20,
    staggerDirection: -1,
  },
});

const paths = [
  {url: "/", component: androidHome},
  {url: "/index", component: androidHome},
  {url: "/activation", component: androidActivation},
  {url: "/signin", component: androidLogin},
  {url: "/report", component: androidReport},

  {url: "/permissions", component: androidPermissions},
  {url: "/bgloc", component: androidBgLoc},
  {url: "/security", component: androidSecurity},
  {url: "/privacy", component: androidPrivacy},
  {url: "/start", component: OnBoarding},
  {url: "/whatsprey", component: WhatsPrey},
  {url: "/pin", component: androidPin},
  {url: "/lock", component: androidLock},
  {url: "/lockmessage", component: androidLockMessage},
  {url: "/lockmessage2", component: androidLockMessage2},
  {url: "/rename", component: androidRename},
  {url: "/location", component: androidLocation},
  {url: "/chrome", component: androidChrome},
  {url: "/accessibility", component: androidAccessibility},
]

const iospaths = [
  { url: '/', component: iosHome },
  { url: '/index', component: iosHome },
  { url: '/activation', component: iosActivation },
  { url: '/signin', component: iosLogin },
  { url: '/permissions', component: iosPermissions },
  { url: '/start', component: OnBoarding },
  { url: '/rename', component: iosRename },
  { url: '/whatsprey', component: WhatsPrey },
];

class App extends React.Component {
  constructor(props) {
    super(props);
    this.state = {}
  }
  componentWillMount() {
    initLang();
  }
  renderer = () => {
    if (onboardingType === 'android') {
      return (
        <Route
          render={
            ({ location, match }) => (
              <PoseGroup>
                <RouteContainer key={location.pathname}>
                  <Switch location={location}>
                    {
                      paths.map((item, key)=>{
                        let setLang = location.pathname.match(/\/(es|en)\//)
                        let path = item.url
                        let lang
                        if(setLang && setLang.length > 0 ){
                          lang = `/${setLang[1]}`
                          I18n.setLocale(setLang[1])
                        } else {
                          lang = ''
                          I18n.setLocale('en')
                        }
                        path = `${lang}${item.url}`
                        return <Route exact path={path} component={item.component} key={key} />
                      })
                    }
                  </Switch>
                </RouteContainer>
              </PoseGroup>
          )}
        />
      )
    } else {
      return (
        <Route
          render={
            ({ location, match }) => (
              <PoseGroup>
                <RouteContainer key={location.pathname}>
                  <Switch location={location}>
                    {
                      iospaths.map((item, key)=>{
                        let setLang = location.pathname.match(/\/(es|en)\//)
                        let path = item.url
                        let lang
                        if(setLang && setLang.length > 0 ){
                          lang = `/${setLang[1]}`
                          I18n.setLocale(setLang[1])
                        } else {
                          lang = ''
                          I18n.setLocale('en')
                        }
                        path = `${lang}${item.url}`
                        return <Route exact path={path} component={item.component} key={key} />
                      })
                    }
                  </Switch>
                </RouteContainer>
              </PoseGroup>
          )}
        />
      );
    }
  };
  render() {
    return (
      <React.Fragment>
        <GlobalStyle />
        <ThemeProvider theme={dark}>
          {this.renderer()}
        </ThemeProvider>
      </React.Fragment>
    )
  }
}

ReactDOM.render(
  <HashRouter>
    <App />
  </HashRouter>,
  document.getElementById('root')
);
