import React from "react";
import styled from "styled-components";
import { darken, shade } from "polished";
import { motion, AnimatePresence } from "framer-motion";

const variantParent = {
  open: {
    transition: { staggerChildren: 0.07, delayChildren: 0.2 },
  },
  closed: {
    transition: { staggerChildren: 0.05, staggerDirection: -1 },
  },
};

const CustomCheckbox = styled(motion.div)`
  position: relative;
  display: grid;
  grid-template-columns: 1.5rem auto;
  grid-template-areas:
    "checkbox label"
    "checkbox description";
  .desc {
    grid-area: description;
    padding: 0 0 0 0.5rem;
    margin: -0.5rem 0 0 0;
  }

  input[type="checkbox"] {
    margin: 0.5rem;
    position: absolute;
    z-index: 100;
    top: 0;
    left: 0;
    opacity: 0;
  }
  input[type="checkbox"]:checked + .check-box,
  .check-box.checked {
    border-color: ${({ theme }) => theme.green};
  }
  input[type="checkbox"]:checked + .check-box::after,
  .check-box.checked::after {
    height: 0.5rem;
    -moz-animation: dothabottomcheck 0.2s ease 0s forwards;
    -o-animation: dothabottomcheck 0.2s ease 0s forwards;
    -webkit-animation: dothabottomcheck 0.2s ease 0s forwards;
    animation: dothabottomcheck 0.2s ease 0s forwards;
  }
  input[type="checkbox"]:checked + .check-box::before,
  .check-box.checked::before {
    height: 2rem;
    -moz-animation: dothatopcheck 0.4s ease 0s forwards;
    -o-animation: dothatopcheck 0.4s ease 0s forwards;
    -webkit-animation: dothatopcheck 0.4s ease 0s forwards;
    animation: dothatopcheck 0.4s ease 0s forwards;
  }
  label {
    margin: 0;
    padding: 0 0 0 0.5rem;
  }
  .check-box {
    width: 1.5rem;
    flex: 0 0 auto;
    overflow: visible;
  }
`;

class Textarea extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      selected_item: this.props.selected_item || false,
    };
    this._className = this._className.bind(this);
  }

  handleFocus = (event) => {
    event.target.select();
  };

  _className() {
    if (this.props.className === undefined) {
      this.setState.className = "";
    } else {
      this.setState.className = this.props.className;
    }
  }

  renderLabel = () => {
    if (this.props.label) {
      return <label htmlFor={this.props.id}>{this.props.label}</label>;
    } else {
      return "";
    }
  };

  render() {
    return (
      <div className={`input ${this.props.className}`}>
        {this.renderLabel()}
        <textarea
          onFocus={(event) => this.handleFocus(event)}
          className={`${this.props.className}`}
          name={this.props.id}
          id={this.props.id}
          defaultValue={!this.props.placeholder ? "" : this.props.placeholder}
        ></textarea>
      </div>
    );
  }
}

class Checkbox extends React.Component {
  constructor(props) {
    super(props);
    // console.log(props)
    this.state = {
      checked: false,
    };
  }

  renderLabel = () => {
    if (this.props.label) {
      return <label htmlFor={this.props.id}>{this.props.label}</label>;
    } else {
      return "";
    }
  };

  render() {
    return (
      <CustomCheckbox className={this.props.className}>
        <input
          id={`${this.props.id}`}
          type="checkbox"
          onChange={() => this.props.onChange}
          className={this.props.variant || "horizontal"}
        />
        <label htmlFor={`${this.props.id}`} className="check-box"></label>
        {this.renderLabel()}
        <AnimatePresence exitBeforeEnter initial={false}>
          <motion.span
            className="desc"
            initial="closed"
            enter="open"
            exit="closed"
            variants={variantParent}
          >
            {this.props.children}
          </motion.span>
        </AnimatePresence>
      </CustomCheckbox>
    );
  }
}

class Range extends React.Component {
  renderLabel = () => {
    if (this.props.label) {
      return <label htmlFor={this.props.id}>{this.props.label}</label>;
    }
  };
  render() {
    return (
      <div {...this.props} className="custom-checkbox">
        <input
          id={`${this.props.id}`}
          type="checkbox"
          defaultChecked={this.props.defaultChecked}
          onChange={this.props.onChange}
          className={this.props.clases || "mount"}
        />
        <label htmlFor={`${this.props.id}`} className="check-box"></label>
        {this.renderLabel()}
        <span className="desc">{this.props.children}</span>
      </div>
    );
  }
}

const InnerStyle = (props) => {
  return `
    .custom-checkbox {
      position: relative;
      display: grid;
      grid-template-columns: 1.5rem auto;
      grid-template-areas: "checkbox label"
                          "checkbox description";
      .desc {
        grid-area: description;
        padding: 0 0 0 0.5rem;
        margin: -0.5rem 0 0 0;
      }
      input {
        margin: 0;
        display: none;
      }
      input[type=checkbox]:checked + .check-box,
      .check-box.checked {
        border-color: ${props.green};
      }
      input[type=checkbox]:checked + .check-box::after,
      .check-box.checked::after {
        height: 0.5rem;
        -moz-animation: dothabottomcheck 0.2s ease 0s forwards;
        -o-animation: dothabottomcheck 0.2s ease 0s forwards;
        -webkit-animation: dothabottomcheck 0.2s ease 0s forwards;
        animation: dothabottomcheck 0.2s ease 0s forwards;
      }
      input[type=checkbox]:checked + .check-box::before,
      .check-box.checked::before {
        height: 2rem;
        -moz-animation: dothatopcheck 0.4s ease 0s forwards;
        -o-animation: dothatopcheck 0.4s ease 0s forwards;
        -webkit-animation: dothatopcheck 0.4s ease 0s forwards;
        animation: dothatopcheck 0.4s ease 0s forwards;
      }
      label {
        margin: 0;
        padding: 0 0 0 0.5rem;
      }
      .check-box {
        width: 1.5rem;
        flex: 0 0 auto;
        overflow: visible;
      }
    }
    // Custom Checkbox
    @keyframes dothabottomcheck {
      0% {
        height: 0;
      }
      100% {
        height: 0.5rem;
      }
    }
    @keyframes dothatopcheck {
      0% {
        height: 0;
      }
      50% {
        height: 0;
      }
      100% {
        height: 1.5rem;
      }
    }

    .check-box {
      height: 1.5rem;
      width: 1.5rem;
      background-color: ${darken(0.05, props.bg)};
      border: 1px solid ${props.linkColor};
      position: relative;
      display: inline-block;
      -moz-box-sizing: border-box;
      -webkit-box-sizing: border-box;
      box-sizing: border-box;
      -moz-transition: border-color ease 0.2s;
      -o-transition: border-color ease 0.2s;
      -webkit-transition: border-color ease 0.2s;
      transition: border-color ease 0.2s;
      cursor: pointer;
    }

    .check-box::before, .check-box::after {
      -moz-box-sizing: border-box;
      -webkit-box-sizing: border-box;
      box-sizing: border-box;
      position: absolute;
      height: 0;
      width: 0.3rem;
      background-color: ${props.green};
      display: inline-block;
      -moz-transform-origin: left top;
      -ms-transform-origin: left top;
      -o-transform-origin: left top;
      -webkit-transform-origin: left top;
      transform-origin: left top;
      content: ' ';
      -webkit-transition: opacity ease .5;
      -moz-transition: opacity ease .5;
      transition: opacity ease .5;
    }

    .check-box::before {
      top: 11px;
      left: 7px;
      -moz-transform: rotate(-135deg);
      -ms-transform: rotate(-135deg);
      -o-transform: rotate(-135deg);
      -webkit-transform: rotate(-135deg);
      transform: rotate(-135deg);
    }

    .check-box::after {
      top: 6px;
      left: 2px;
      -moz-transform: rotate(-45deg);
      -ms-transform: rotate(-45deg);
      -o-transform: rotate(-45deg);
      -webkit-transform: rotate(-45deg);
      transform: rotate(-45deg);
    }

    .vertical {
      display: grid;
    }

    .horizontal {
      display: grid;
      grid-template-columns: ${props.fontSize} auto;
      gap: 0.5rem;
    }

    .mount {
      display: grid;
      position: relative;
      label {
        width: 100%;
        padding: 0 1rem;
        position: absolute;
        font-family: ${props.mono};
        top: calc(${props.fontSize} - 0.1vw);
        font-size: calc(${props.fontSize} - 0.1vw);
        color: ${shade(0.3, props.fontColor)};
        overflow: hidden;
        white-space: nowrap;
        text-overflow: ellipsis;
      }
      label {
        width: 100%;
        z-index: 10;
      }
      input, select, textarea {
        width: 100%;
        z-index: 5;
      }
      input[type="text"],input[type="password"],input[type="search"],input[type="number"],input[type="email"], select, textarea {
        outline: none;
        -webkit-appearance: none;
        padding: 2.5rem 1rem 1rem;
        line-height: 1.3;
        border-radius: 0;
      }
    }
  `;
};

const InputStyle = (props) => {
  return InnerStyle(props);
};

const InputS = styled(motion.div)`
  ${(props) => InnerStyle(props.theme)}
`;

const Input = React.forwardRef(function Input({ ...props }, ref) {
  const renderLabel = () => {
    if (props.label) {
      return <label htmlFor={props.id}>{props.label}</label>;
    } else {
      return "";
    }
  };
  const renderType = () => {
    switch (props.type) {
      case "textarea":
        return <Textarea {...props} />;
      case "checkbox":
        return <Checkbox {...props} />;
      case "range":
        return <Range {...props} />;
      default:
        return (
          <div className={`input ${props.className}`}>
            {renderLabel()}
            <input
              ref={ref}
              id={props.id}
              type={props.type}
              value={props.value}
              placeholder={!props.placeholder ? "" : props.placeholder}
              {...props}
            />
            {props.children}
          </div>
        );
    }
  };
  return <InputS>{renderType()}</InputS>;
});

export { Input, InputStyle };
