import React from "react";
import { Wizard, Steps, Step } from "react-albus";
import { I18n } from "react-i18nify-lite";
import permOne from "../images/onboarding/ilust/permissions-01.png";
import logomono from "../images/branding/prey-logo-monotono-alt.svg";
import { isNativeWindows, sendMessageToIos } from "./commons";

export default class Permissions extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      data: {},
    };
  }

  componentDidMount() {
    this.handlePermissionResult = (e) => {
      const { permission, granted } = e.detail;
      if ((permission === "location", granted === true)) {
        this.props.history.push(`/${I18n._locale}/signin`);
      }
    };

    window.addEventListener(
      "preyPermissionResult",
      this.handlePermissionResult,
    );
  }

  componentWillUnmount() {
    window.removeEventListener(
      "preyPermissionResult",
      this.handlePermissionResult,
    );
  }

  handleNext = () => {
    if (isNativeWindows()) {
      sendMessageToIos("authlocation");
    } else {
      window.location.href = "/";
    }
  };

  render() {
    return (
      <div className="perms fs-onboarding regular inverted">
        <div className="column">
          <div className="permissions-brand">
            <img src={logomono} alt="Prey" className="permissions-brand-logo" />
          </div>
          <h4 className="heading">{I18n.t("ios.permissions.title")}</h4>
          <Wizard>
            <Steps>
              <Step
                id="location"
                render={({ next }) => (
                  <div className="step ios-permissions-step">
                    <p>
                      {I18n.t("ios.permissions.location.title")}
                      <br />
                      <ul>
                        <li>{I18n.t("ios.permissions.location.list.one")}</li>
                        <li>{I18n.t("ios.permissions.location.list.two")}</li>
                        <li>{I18n.t("ios.permissions.location.list.three")}</li>
                      </ul>
                      <br />
                      {I18n.t("ios.permissions.location.desc")}{" "}
                      <b>{I18n.t("ios.permissions.location.allow")}</b>.
                    </p>
                    <figure>
                      <img src={permOne} className="first" alt="permOne" />
                    </figure>
                    <button
                      className="ob-btn ob-btn-compact btn-centered"
                      onClick={this.handleNext}
                    >
                      {I18n.t("next")}
                    </button>
                  </div>
                )}
              />
            </Steps>
          </Wizard>
        </div>
      </div>
    );
  }
}
