import React from "react";
import { Link } from "react-router-dom";
import { I18n } from "react-i18nify-lite";
import { Group } from "../assets/stash";
import logomono from "../images/branding/prey-logo-monotono-alt.svg";
import LegalFooter from "../common/LegalFooter";

const initAdminActive = () => {
  if (window.Android) {
    return window.Android.initAdminActive();
  } else {
    return false;
  }
};

const initCamera = () => {
  if (window.Android) {
    return window.Android.initCamera();
  } else {
    return false;
  }
};
const initWriteStorage = () => {
  if (window.Android) {
    return window.Android.initWriteStorage();
  } else {
    return false;
  }
};
const initLocation = () => {
  if (window.Android) {
    return window.Android.initLocation();
  } else {
    return false;
  }
};
const initBackgroundLocation = () => {
  if (window.Android) {
    return window.Android.initBackgroundLocation();
  } else {
    return false;
  }
};
const initAndroid10OrAbove = () => {
  if (window.Android) {
    return window.Android.initAndroid10OrAbove();
  } else {
    return false;
  }
};
const initXiaomi = () => {
  if (window.Android) {
    return window.Android.initXiaomi();
  } else {
    return false;
  }
};
const initHuawei = () => {
  if (window.Android) {
    return window.Android.initHuawei();
  } else {
    return false;
  }
};
const initAccessibility = () => {
  if (window.Android) {
    return window.Android.initAccessibility();
  } else {
    return false;
  }
};
const initConfigure = () => {
  if (window.Android) {
    return window.Android.initConfigure();
  } else {
    return false;
  }
};

class Permission2 extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      hasAdminActive: initAdminActive(),
      hasLocation: initLocation(),
      hasCamera: initCamera(),
      hasWriteStorage: initWriteStorage(),
      hasBackgroundLocation: initBackgroundLocation(),
      isAndroid10OrAbove: initAndroid10OrAbove(),
      hasConfigure: initConfigure(),
      hasAccessibility: initAccessibility(),
      xiaomiAlert: initXiaomi(),
      huaweiAlert: initHuawei(),
    };
  }

  handleClick = () => {
    if (window.Android) {
      window.Android.givePermissions();
    } else {
      this.props.history.push(`/${I18n._locale}/bgloc`);
    }
  };

  handleClickNext = (e) => {
    if (window.Android) {
      window.Android.skipPermissions();
    } else {
      this.props.history.push(`/${I18n._locale}/signin`);
      return;
    }
    if (initConfigure()) {
      this.props.history.push(`/${I18n._locale}/`);
    } else {
      this.props.history.push(`/${I18n._locale}/signin`);
    }
  };

  render() {
    return (
      <div className="security fs-onboarding regular inverted android-permissions-redesign">
        <div className="column">
          <div className="android-permissions-header">
            <img src={logomono} alt="Prey" className="permissions-brand-logo" />
          </div>
          <div className="android-permissions-panel">
            <h4 className="heading">{I18n.t("permissions.title")}</h4>
            {this.state.isAndroid10OrAbove && (
              <div className="perm-card">
                <h5>{I18n.t("permissions.category_location")}</h5>
                <p>{I18n.t("permissions.location.background1")}</p>
                <p>{I18n.t("permissions.location.background2")}</p>
              </div>
            )}

            {this.state.xiaomiAlert && (
              <div className="perm-card">
                <h5>{I18n.t("permissions.xiaomi.head")}</h5>
                <p dangerouslySetInnerHTML={{ __html: I18n.t("permissions.xiaomi.body") }} />
              </div>
            )}

            {this.state.huaweiAlert && (
              <div className="perm-card">
                <h5>{I18n.t("permissions.huawei.head")}</h5>
                <p dangerouslySetInnerHTML={{ __html: I18n.t("permissions.huawei.body") }} />
              </div>
            )}

            {!this.state.hasLocation && (
              <div className="perm-card">
                <h5>{I18n.t("permissions.location.head")}</h5>
                <p>{I18n.t("permissions.location.body")}</p>
              </div>
            )}

            {!this.state.hasCamera && (
              <div className="perm-card">
                <h5>{I18n.t("permissions.camera.head")}</h5>
                <p>{I18n.t("permissions.camera.body")}</p>
              </div>
            )}

            {!this.state.hasWriteStorage && (
              <div className="perm-card">
                <h5>{I18n.t("permissions.storage.head")}</h5>
                <p>{I18n.t("permissions.storage.body")}</p>
              </div>
            )}

            {!this.state.hasAdminActive && (
              <div className="perm-card">
                <h5>{I18n.t("permissions.administrator_permission.head")}</h5>
                <p>{I18n.t("permissions.administrator_permission.body")}</p>
              </div>
            )}
          </div>
          <Link
            to="#"
            onClick={this.handleClick}
            className="ob-btn ob-btn-compact btn-centered"
          >
            <span>{I18n.t("permissions.approve")}</span>
          </Link>
        </div>
        <LegalFooter />
      </div>
    );
  }
}

export default Permission2;
